#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        if (N < 10) {
            printf("Thanks for helping Chef!\n");
        } else {
            printf("-1\n");
        }
    }
    return 0;
}

